632	njs_generator_init(njs_generator_t *generator, njs_str_t *file,
633	    njs_int_t depth, njs_bool_t runtime)
634	{
635	    njs_memzero(generator, sizeof(njs_generator_t));
636	
637	    njs_queue_init(&generator->stack);
638	
639	    generator->file = *file;
640	    generator->depth = depth;
641	    generator->runtime = runtime;
642	
643	    return NJS_OK;
644	}
