656	njs_inline njs_int_t
657	njs_generator_after(njs_vm_t *vm, njs_generator_t *generator,
658	    njs_queue_link_t *link, njs_parser_node_t *node,
659	    njs_generator_state_func_t state, void *ctx, size_t size)
660	{
661	    njs_generator_stack_entry_t  *entry;
662	
663	    entry = njs_mp_alloc(vm->mem_pool, sizeof(njs_generator_stack_entry_t));
664	    if (njs_slow_path(entry == NULL)) {
665	        return NJS_ERROR;
666	    }
667	
668	    entry->state = state;
669	    entry->node = node;
670	    entry->context = ctx;
671	
672	    njs_queue_insert_before(link, &entry->link);
673	
674	    if (size > 0) {
675	        entry->context = njs_mp_alloc(vm->mem_pool, size);
676	        if (njs_slow_path(entry->context == NULL)) {
677	            return NJS_ERROR;
678	        }
679	
680	        memcpy(entry->context, ctx, size);
681	    }
682	
683	    return NJS_OK;
684	}
