687	njs_inline njs_int_t
688	njs_generator_stack_pop(njs_vm_t *vm, njs_generator_t *generator, void *ctx)
689	{
690	    njs_queue_link_t             *link;
691	    njs_generator_stack_entry_t  *entry;
692	
693	    entry = njs_queue_link_data(njs_queue_first(&generator->stack),
694	                                njs_generator_stack_entry_t, link);
695	
696	    link = njs_queue_first(&generator->stack);
697	    njs_queue_remove(link);
698	
699	    if (ctx != NULL) {
700	        njs_mp_free(vm->mem_pool, ctx);
701	    }
702	
703	    generator->context = entry->context;
704	
705	    njs_generator_next(generator, entry->state, entry->node);
706	
707	    njs_mp_free(vm->mem_pool, entry);
708	
709	    return NJS_OK;
710	}
