njs_vm_code_t *
njs_generate_scope(njs_vm_t *vm, njs_generator_t *generator,
    njs_parser_scope_t *scope, const njs_str_t *name)
{
    u_char                 *p, *code_start;
    size_t                 code_size, prelude;
    int64_t                nargs;
    njs_int_t              ret;
    njs_arr_t              *arr;
    njs_uint_t             index, n;
    njs_vm_code_t          *code;
    njs_declaration_t      *declr;
    njs_vmcode_function_t  *fun;

    generator->code_size = 128;

    p = njs_mp_alloc(vm->mem_pool, generator->code_size);
    if (njs_slow_path(p == NULL)) {
        njs_memory_error(vm);
        return NULL;
    }

    generator->code_start = p;
    generator->code_end = p;

    nargs = njs_generate_lambda_variables(vm, generator, scope->top);
    if (njs_slow_path(nargs < NJS_OK)) {
        return NULL;
    }

    if (vm->codes == NULL) {
        vm->codes = njs_arr_create(vm->mem_pool, 4, sizeof(njs_vm_code_t));
        if (njs_slow_path(vm->codes == NULL)) {
            return NULL;
        }
    }

    index = vm->codes->items;
    code = njs_arr_add(vm->codes);
    if (njs_slow_path(code == NULL)) {
        njs_memory_error(vm);
        return NULL;
    }

    code->lines = NULL;

    if (vm->options.backtrace) {
        code->lines = njs_arr_create(vm->mem_pool, 4,
                                     sizeof(njs_vm_line_num_t));
        if (njs_slow_path(code->lines == NULL)) {
            njs_memory_error(vm);
            return NULL;
        }

        generator->lines = code->lines;
    }

    generator->closures = njs_arr_create(vm->mem_pool, 4, sizeof(njs_index_t));
    if (njs_slow_path(generator->closures == NULL)) {
        return NULL;
    }

    scope->closures = generator->closures;

    njs_queue_init(&generator->stack);

    njs_generator_next(generator, njs_generate, scope->top);

    ret = njs_generator_after(vm, generator,
                              njs_queue_first(&generator->stack), NULL,
                              njs_generate_scope_end, NULL, 0);
    if (njs_slow_path(ret != NJS_OK)) {
        return NULL;
    }

    do {
        ret = generator->state(vm, generator, generator->node);
        if (njs_slow_path(ret != NJS_OK)) {
            return NULL;
        }

    } while (generator->state != NULL);

    arr = scope->declarations;
    scope->declarations = NULL;

    if (arr != NULL && arr->items > 0) {
        declr = arr->start;
        prelude = sizeof(njs_vmcode_function_t) * arr->items;
        code_size = generator->code_end - generator->code_start;

        for (n = 0; n < arr->items; n++) {
            fun = (njs_vmcode_function_t *) njs_generate_reserve(vm,
                                     generator, sizeof(njs_vmcode_function_t));
            if (njs_slow_path(fun == NULL)) {
                njs_memory_error(vm);
                return NULL;
            }

            generator->code_end += sizeof(njs_vmcode_function_t);
            fun->code = NJS_VMCODE_FUNCTION;

            fun->lambda = declr[n].lambda;
            fun->async = declr[n].async;
            fun->retval = declr[n].index;
        }

        code_start = njs_mp_alloc(vm->mem_pool, code_size + prelude);
        if (njs_slow_path(code_start == NULL)) {
            njs_memory_error(vm);
            return NULL;
        }

        memcpy(code_start, &generator->code_start[code_size], prelude);
        memcpy(&code_start[prelude], generator->code_start, code_size);

        njs_mp_free(vm->mem_pool, generator->code_start);

        generator->code_start = code_start;
        generator->code_end = code_start + code_size + prelude;
    }

    code = njs_arr_item(vm->codes, index);
    code->start = generator->code_start;

